function.arguments:
{"path": "~/hermes_home_setup/check_env.ps1", "content": "#!/usr/bin/env pwsh
# Hermes Windows环境检查脚本
# 运行: powershell -ExecutionPolicy Bypass -File check_env.ps1

Write-Host "=== Hermes Windows 环境检查 ===" -ForegroundColor Cyan
Write-Host "检查时间: $(Get-Date)" -ForegroundColor Gray
Write-Host ""

# 1. 检查Python
Write-Host "1. 检查Python安装..." -ForegroundColor Yellow
$pythonVersion = ""
try {
    $pythonVersion = python --version 2>&1
    Write-Host "   Python版本: $pythonVersion" -ForegroundColor Green
} catch {
    Write-Host "   ❌ Python未安装或不在PATH中" -ForegroundColor Red
}

# 2. 检查pip
Write-Host "2. 检查pip..." -ForegroundColor Yellow
try {
    $pipVersion = pip --version 2>&1
    Write-Host "   pip版本: $pipVersion" -ForegroundColor Green
} catch {
    Write-Host "   ❌ pip未安装或不在PATH中" -ForegroundColor Red
}

# 3. 检查Git（可选）
Write-Host "3. 检查Git..." -ForegroundColor Yellow
try {
    $gitVersion = git --version 2>&1
    Write-Host "   Git版本: $gitVersion" -ForegroundColor Green
} catch {
    Write-Host "   ⚠️ Git未安装（可选，用于克隆技能仓库）" -ForegroundColor Yellow
}

# 4. 检查Ollama（如果已安装）
Write-Host "4. 检查Ollama..." -ForegroundColor Yellow
$ollamaRunning = $false
try {
    $ollamaResponse = Invoke-WebRequest -Uri "http://localhost:11434/api/tags" -UseBasicParsing -TimeoutSec 3 -ErrorAction SilentlyContinue
    if ($ollamaResponse.StatusCode -eq 200) {
        $ollamaRunning = $true
        Write-Host "   ✅ Ollama服务正在运行" -ForegroundColor Green
    }
} catch {
    Write-Host "   ℹ️ Ollama未运行或不在端口11434" -ForegroundColor Gray
}

# 5. 检查网络连接
Write-Host "5. 检查网络连接..." -ForegroundColor Yellow
try {
    $testConnection = Test-Connection -ComputerName "api.deepseek.com" -Count 1 -Quiet -ErrorAction SilentlyContinue
    if ($testConnection) {
        Write-Host "   ✅ 可访问DeepSeek API" -ForegroundColor Green
    } else {
        Write-Host "   ⚠️ 无法访问DeepSeek API（可能需代理）" -ForegroundColor Yellow
    }
} catch {
    Write-Host "   ⚠️ 网络检查失败" -ForegroundColor Yellow
}

# 6. 磁盘空间检查
Write-Host "6. 检查磁盘空间..." -ForegroundColor Yellow
$drive = Get-PSDrive -Name C -ErrorAction SilentlyContinue
if ($drive) {
    $freeGB = [math]::Round($drive.Free / 1GB, 2)
    $totalGB = [math]::Round($drive.Used / 1GB + $drive.Free / 1GB, 2)
    Write-Host "   C盘可用空间: ${freeGB}GB / ${totalGB}GB" -ForegroundColor Green
    if ($freeGB -lt 10) {
        Write-Host "   ⚠️ 磁盘空间不足（建议至少10GB）" -ForegroundColor Red
    }
}

# 7. 检查防火墙设置
Write-Host "7. 检查防火墙端口..." -ForegroundColor Yellow
$portsToCheck = @(11434, 8642, 8648, 3001, 8765)
foreach ($port in $portsToCheck) {
    $listener = Get-NetTCPConnection -LocalPort $port -State Listen -ErrorAction SilentlyContinue
    if ($listener) {
        Write-Host "   ⚠️ 端口 ${port} 已被占用" -ForegroundColor Yellow
    }
}

# 8. 检查WSL状态（如安装）
Write-Host "8. 检查WSL状态..." -ForegroundColor Yellow
try {
    $wslInfo = wsl --list --verbose 2>&1
    if ($LASTEXITCODE -eq 0) {
        Write-Host "   ✅ WSL已安装" -ForegroundColor Green
        Write-Host "   $wslInfo" -ForegroundColor Gray
    } else {
        Write-Host "   ℹ️ WSL未安装（可选）" -ForegroundColor Gray
    }
} catch {
    Write-Host "   ℹ️ WSL未安装（可选）" -ForegroundColor Gray
}

Write-Host ""
Write-Host "=== 检查完成 ===" -ForegroundColor Cyan

# 总结和建议
Write-Host ""
Write-Host "📋 建议：" -ForegroundColor Cyan

if (-not $pythonVersion) {
    Write-Host "1. 请安装Python 3.8+：https://www.python.org/downloads/" -ForegroundColor Yellow
}

if (-not $ollamaRunning) {
    Write-Host "2. 建议安装Ollama（节约API费用）：" -ForegroundColor Yellow
    Write-Host "   a. 下载：https://ollama.com/download/windows" -ForegroundColor Gray
    Write-Host "   b. 运行：ollama serve" -ForegroundColor Gray
    Write-Host "   c. 拉取模型：ollama pull qwen2.5:7b" -ForegroundColor Gray
}

Write-Host "3. 根据你的选择执行安装：" -ForegroundColor Yellow
Write-Host "   - 选项A（直接安装）：运行 install_direct.ps1" -ForegroundColor Gray
Write-Host "   - 选项B（WSL安装）：参考 install_wsl.md" -ForegroundColor Gray
Write-Host "   - 选项C（简化架构）：运行 setup_simple_server.py" -ForegroundColor Gray

Write-Host ""
Write-Host "💡 安装完成后，可以运行：hermes web --port 8658 启动Web界面" -ForegroundColor Green"}
